SELECT count(*) FROM cast_info, title, movie_companies, movie_keyword, name, keyword, aka_name, movie_info, info_type WHERE cast_info.movie_id = title.id AND movie_companies.movie_id = title.id AND movie_keyword.movie_id = title.id AND cast_info.person_id = name.id AND movie_keyword.keyword_id = keyword.id AND aka_name.person_id = name.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id;